            let receiverKey = dev + "intf " + oifIntfId+ " source "+str(_source) + " " + str(group)

            if !dictHasKey(result,receiverKey){
                    result[receiverKey] = newDict()
                    result[receiverKey]["mac address"] = dev
                    result[receiverKey]["source"] = str(_source)
                    result[receiverKey]["group"] = str(_group)
                    result[receiverKey]["flowBw"] = flowBw
                    result[receiverKey]["On hostname"] = devDetails["hostname"]
                    result[receiverKey]["sender"] = false
                    result[receiverKey]["receiver"] = true
                    result[receiverKey]["has inactive receiver"] = isInactiveReceiver
                    result[receiverKey]["oifs ---> oif neighbor information"] = ""
                    result[receiverKey]["oif neighbor mac address"] = neighborDevId
                    result[receiverKey]["neighbor information --> iif"] = iifneighborHostname +" interface "+  iifneighborIntfId + " -> " +iifintfId
                    result[receiverKey]["iif neighbor mac address"] = iifneighborHostname
                }

            result[receiverKey]["oifs ---> oif neighbor information"] =  oifIntfId +" with trackingId " +str(oifDetail["trackingId"])+ " -> "+  neighborHostname+" interface "+ neighborIntfId + "\n"
            result[receiverKey]["receiver"] = true
        }
        if receiverKey == ""{
                let receiverKey = dev+ " source "+str(_source) + " " + str(group)
        }
