        if ! dictHasKey(result, dev){
            result[resultKey] = newDict()
            result[resultKey]["mac address"] = dev
            result[resultKey]["flowBw"] = ""
            result[resultKey]["group"] = group
            result[resultKey]["source"] = str(_source)
            result[resultKey]["group"] = str(_group)
            if !dictHasKey(result[resultKey], "sender"){
            result[resultKey]["sender"] = false
            }
            if !dictHasKey(result[resultKey], "receiver"){
            result[resultKey]["receiver"] = false
            }
            result[resultKey]["On hostname"] = devDetails["hostname"]
            result[resultKey]["flowBw"] = flowBw
            result[resultKey]["has inactive receiver"] = isInactiveReceiver
            let neighborHostname = (devDetails["iif"]["neighborHostname"] != "") ? devDetails["iif"]["neighborHostname"] : "N/A"
            let neighborIntfId = (devDetails["iif"]["neighborIntfId"] != "") ? devDetails["iif"]["neighborIntfId"] : "N/A"
