            let neighborDevId = (oifDetail["neighborDevId"] != "") ? oifDetail["neighborDevId"] : "N/A"
            result[resultKey]["oif neighbor mac address"] = neighborDevId
            result[resultKey]["oifs ---> oif neighbor information"] = result[resultKey]["oifs ---> oif neighbor information"] + oifIntfId +" -> "+  neighborDevId +" interface "+ neighborIntfId + "\n"

        }
    }
}
